var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"그간 무탈하게 지내셨나요, 주인님.","JPN":"いかがお過ごしでしたか、ご主人様。","ENG":"I hope all is well with you, Master.","TWN":"你過得還好嗎，主人。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그라운드 원에서 있었던 사건에 대한 참고인 조사가 오늘로 마무리되었습니다.","JPN":"グラウンド・ワンでの事件に関する参考人調査が本日で終わりました。","ENG":"Today marked the last day of my interview at Ground One on the latest incident.","TWN":"對於在G1發生的事件，相關證人的調查今天已經結束了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"맨션에 대해선 정보부 분들도 일찍부터 조사하고 계셨기에, 증언을 조건으로 선처 받을 수 있었습니다.","JPN":"マンションに関しては情報部の方もかねてから調べており、証言を条件に善処されることができました。","ENG":"It turns out the intelligence agents were already investigating the Mansion, so I received leniency in return for my testimony.","TWN":"情報部的人之前就已經開始調查曼森，作為從寬處理的條件，我答應作證。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"주인님께서도 저와 같은 풍경을 보고 계실까 궁금한 마음에, 이렇게 편지를 적어 올립니다.","JPN":"ご主人様も私と同じ風景を眺めているのか気になり、こうしてお手紙をしたためました。","ENG":"As I write this letter, I'm curious if you also see a similar scene unfold before you.","TWN":"不知道主人您是否和我看著同樣的景色，特此寫信向您問安。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"저희가 있는 도시에는 오늘 첫눈이 내렸습니다. ","JPN":"私たちの住む都市には本日初雪が降りました。 ","ENG":"It snowed for the first time this year in the city. ","TWN":"我們的城市今天下了第一場雪。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"오오! 선배님들! 조사 받느라 고생하셨슴다!","JPN":"おお、先輩方！　調査お疲れ様っす！","ENG":"Ooh, Senior Maids! I'm glad you're finally done with the investigation!","TWN":"噢噢！前輩們！你們接受調查辛苦了！"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"너 쪽팔리게 선배라고 부르지 말랬지. 왜 내가 네 선배야?","JPN":"ねえ、先輩って呼ぶのはやめてって言ったでしょう。あと、なんで私があんたの先輩なの？","ENG":"Like I said, we are not your Senior! Stop calling us that!","TWN":"跟你說了不要叫我前輩，我怎麼是你的前輩了？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"헤헤. 모네보다 일찍 메이드가 되셨으니까 그렇슴다!","JPN":"ヘヘッ、モネより先にメイドになったからっす！","ENG":"Heh heh, it's because you became a maid earlier than me, ma'am!","TWN":"嘿嘿，因為您比莫妮更早成為了女僕啊！"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"모네는 식구가 늘게 되어 무척 기쁜 듯합니다.","JPN":"モネは家族が増えたことがとても嬉しいみたいです。","ENG":"Mone seems to be very excited with the addition of new family.","TWN":"多了個家人，莫妮似乎很開心。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"리코리스는 조사 내내 마크란 분이 자기 상사라고 했는데, 그런 이름의 요원은 없다는 응답만 받았어요.","JPN":"リコリスは調査の時に、マークという方が自分の上司と言っていましたが、そのような名前の要員は存在しないという返答でした。","ENG":"During the interviews, Lycoris insisted that she was working for someone named Mark, but the agency folks kept saying there was no person by that name.","TWN":"莉克麗絲接受調查的時候說一個叫馬克的人是自己的上司，但他們說沒有那樣的人。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"이후에는 양측 모두 사정을 감추고 싶어하는 눈치였기에 모른 척 하기로 했습니다.","JPN":"その後は双方とも事情を隠したい様子だったので、知らないふりをすることにしました。","ENG":"It seemed like both sides were trying to keep their stories discreet, so I decided to turn a blind eye to them.","TWN":"之後感覺雙方都不想提及此事，所以我也裝作不知道。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"여기까지 나오실 필요는 없었어요. 메이드장님.","JPN":"お迎えに来てくださらなくてもいいんですよ、メイド長。","ENG":"You didn't have to come out all the way here, Chief Maid.","TWN":"你不用特意出來的，女僕長大人。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"후훗. 갑자기 눈 오는 거리를 산책하고 싶어지더군요.","JPN":"ふふっ、突然雪の降る街を散歩したくなりました。","ENG":"Hah hah, I just wanted to go for a stroll in the snow.","TWN":"呼呼，我只是突然想在雪地裡散步而已。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"수첩이 그새 많이 닳았네요. 가는 길에 하나 더 사야겠어요.","JPN":"手帳がかなり古くなってしまいましたね。一冊買って帰りましょうか。","ENG":"Your notepad has worn out a lot. Let's get you a new one on the way back.","TWN":"手冊都這麼破了，路上買個新的吧。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"아, 그건......","JPN":"ああ、それは……","ENG":"Oh, erm...","TWN":"啊，這是……"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......땡큐베리감사, 입니다.","JPN":"……あざっすベリーサンキュー、です。","ENG":"TYSM, if that's how they say it.","TWN":"……非常感謝。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};